// NanoClaw Electron App — Renderer

// --- State ---
let token = '';
let ws: WebSocket | null = null;
let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
let currentGroupJid = '';
let groups: Array<{ jid: string; name: string; folder: string; isMain?: boolean }> = [];
let messages: Array<{
  id: string;
  chat_jid: string;
  sender: string;
  sender_name: string;
  content: string;
  timestamp: string;
  is_from_me: boolean;
  is_bot_message: boolean;
}> = [];

// --- DOM refs ---
const tokenScreen = document.getElementById('token-screen')!;
const tokenInput = document.getElementById('token-input') as HTMLInputElement;
const tokenConnectBtn = document.getElementById('token-connect')!;
const tokenError = document.getElementById('token-error')!;

const mainScreen = document.getElementById('main-screen')!;
const sidebar = document.getElementById('sidebar')!;
const sidebarCollapse = document.getElementById('sidebar-collapse')!;
const groupsList = document.getElementById('groups-list')!;
const tasksList = document.getElementById('tasks-list')!;
const refreshGroupsBtn = document.getElementById('refresh-groups')!;
const connectionStatus = document.getElementById('connection-status')!;

const chatHeader = document.getElementById('chat-header')!;
const chatGroupName = document.getElementById('chat-group-name')!;
const chatGroupFolder = document.getElementById('chat-group-folder')!;
const clearChatBtn = document.getElementById('clear-chat')!;

const messagesEl = document.getElementById('messages')!;
const messagesEmpty = document.getElementById('messages-empty')!;
const typingIndicator = document.getElementById('typing-indicator')!;

const inputArea = document.getElementById('input-area')!;
const messageInput = document.getElementById('message-input') as HTMLTextAreaElement;
const sendBtn = document.getElementById('send-btn')!;
const attachBtn = document.getElementById('attach-btn')!;
const fileInput = document.getElementById('file-input') as HTMLInputElement;
const fileDropZone = document.getElementById('file-drop-zone')!;

// --- Helpers ---
function apiFetch(path: string, options?: RequestInit): Promise<Response> {
  const headers: Record<string, string> = { 'Content-Type': 'application/json' };
  if (token) headers['Authorization'] = `Bearer ${token}`;
  return fetch(`http://localhost:3000${path}`, { ...options, headers });
}

function formatTime(ts: string): string {
  const d = new Date(parseInt(ts));
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

function formatDate(ts: string): string {
  const d = new Date(parseInt(ts));
  const today = new Date();
  if (d.toDateString() === today.toDateString()) return 'Today';
  const yesterday = new Date(today);
  yesterday.setDate(today.getDate() - 1);
  if (d.toDateString() === yesterday.toDateString()) return 'Yesterday';
  return d.toLocaleDateString();
}

function escapeHtml(s: string): string {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// Configure marked for safe rendering
declare const marked: any;
declare const hljs: any;

function renderMarkdown(text: string): string {
  if (typeof marked === 'undefined') return escapeHtml(text);
  try {
    // Configure marked options
    marked.setOptions({
      breaks: true,
      gfm: true,
      highlight: (code: string, lang: string) => {
        if (typeof hljs !== 'undefined' && lang && hljs.getLanguage(lang)) {
          try {
            return hljs.highlight(code, { language: lang }).value;
          } catch {
            return code;
          }
        }
        return code;
      },
    });
    return marked.parse(text) as string;
  } catch {
    return escapeHtml(text);
  }
}

function setConnectionStatus(status: 'connected' | 'connecting' | 'disconnected') {
  connectionStatus.className = `conn-status ${status}`;
  const label = connectionStatus.querySelector('.conn-label')!;
  label.textContent = status === 'connected' ? 'Connected' : status === 'connecting' ? 'Connecting...' : 'Disconnected';
}

// --- UI Rendering ---
function renderGroups() {
  groupsList.innerHTML = '';
  for (const group of groups) {
    const el = document.createElement('div');
    el.className = `list-item${group.jid === currentGroupJid ? ' active' : ''}`;
    el.innerHTML = `
      <span class="item-name">${escapeHtml(group.name)}</span>
      ${group.isMain ? '<span class="item-badge">main</span>' : ''}
    `;
    el.addEventListener('click', () => selectGroup(group.jid));
    groupsList.appendChild(el);
  }
}

function renderMessages() {
  if (messages.length === 0) {
    messagesEmpty.style.display = 'flex';
    // Clear all message elements
    const existing = messagesEl.querySelectorAll('.message');
    existing.forEach((el) => el.remove());
    return;
  }

  messagesEmpty.style.display = 'none';

  // Clear and re-render all messages
  const existing = messagesEl.querySelectorAll('.message');
  existing.forEach((el) => el.remove());

  for (const msg of messages) {
    const div = document.createElement('div');
    const isUser = msg.is_from_me;
    const isSystem = msg.sender === 'system';

    if (isSystem) {
      div.className = 'message system';
      div.textContent = msg.content;
    } else {
      div.className = `message ${isUser ? 'user' : 'assistant'}`;
      const renderedContent = isUser ? escapeHtml(msg.content) : renderMarkdown(msg.content);
      div.innerHTML = `
        ${msg.sender_name ? `<span class="msg-sender">${escapeHtml(msg.sender_name)}</span>` : ''}
        <div class="msg-content">${renderedContent}</div>
        <span class="msg-time">${formatTime(msg.timestamp)}</span>
      `;
    }

    messagesEl.appendChild(div);
  }

  // Scroll to bottom
  messagesEl.scrollTop = messagesEl.scrollHeight;
}

function updateChatHeader() {
  if (!currentGroupJid) {
    chatGroupName.textContent = 'Select a group';
    chatGroupFolder.textContent = '';
    return;
  }
  const group = groups.find((g) => g.jid === currentGroupJid);
  if (group) {
    chatGroupName.textContent = group.name;
    chatGroupFolder.textContent = group.isMain ? '(main)' : `@ ${group.folder}`;
  }
}

// --- API calls ---
async function loadGroups() {
  try {
    const res = await apiFetch('/api/groups');
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = (await res.json()) as { groups: typeof groups };
    groups = data.groups;
    renderGroups();
  } catch (err) {
    console.error('Failed to load groups:', err);
  }
}

async function loadTasks() {
  if (!currentGroupJid) return;
  const folder = currentGroupJid.replace('web:', '');
  try {
    const res = await apiFetch(`/api/tasks?folder=${encodeURIComponent(folder)}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = (await res.json()) as { tasks: Array<{ id: string; prompt: string; status: string }> };
    tasksList.innerHTML = '';
    if (data.tasks.length === 0) {
      const el = document.createElement('div');
      el.className = 'list-item';
      el.style.color = 'var(--text-muted)';
      el.style.cursor = 'default';
      el.textContent = 'No active tasks';
      tasksList.appendChild(el);
      return;
    }
    for (const task of data.tasks.slice(0, 10)) {
      const el = document.createElement('div');
      el.className = 'list-item';
      el.title = task.prompt;
      el.innerHTML = `<span class="item-name">${escapeHtml(task.prompt.slice(0, 40))}${task.prompt.length > 40 ? '…' : ''}</span>`;
      tasksList.appendChild(el);
    }
  } catch (err) {
    console.error('Failed to load tasks:', err);
  }
}

async function loadMessages() {
  if (!currentGroupJid) return;
  const since = '0';
  try {
    const res = await apiFetch(`/api/messages?jid=${encodeURIComponent(currentGroupJid)}&since=${since}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = (await res.json()) as { messages: typeof messages };
    messages = data.messages;
    renderMessages();
  } catch (err) {
    console.error('Failed to load messages:', err);
  }
}

// --- WebSocket ---
function connectWS() {
  if (ws && ws.readyState === WebSocket.OPEN) return;

  setConnectionStatus('connecting');
  const wsUrl = token
    ? `ws://localhost:3000/ws?token=${encodeURIComponent(token)}`
    : 'ws://localhost:3000/ws';
  ws = new WebSocket(wsUrl);

  ws.onopen = () => {
    setConnectionStatus('connected');
    if (reconnectTimer) {
      clearTimeout(reconnectTimer);
      reconnectTimer = null;
    }
    if (currentGroupJid) {
      sendWs({ type: 'select_group', chatJid: currentGroupJid });
    }
  };

  ws.onclose = () => {
    setConnectionStatus('disconnected');
    ws = null;
    // Reconnect after 3 seconds
    reconnectTimer = setTimeout(connectWS, 3000);
  };

  ws.onerror = (err) => {
    console.error('WS error:', err);
    setConnectionStatus('disconnected');
  };

  ws.onmessage = (e) => {
    try {
      const msg = JSON.parse(e.data) as Record<string, unknown>;
      handleWsMessage(msg);
    } catch {
      console.error('Failed to parse WS message:', e.data);
    }
  };
}

function sendWs(payload: Record<string, unknown>) {
  if (ws && ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify(payload));
  }
}

function handleWsMessage(msg: Record<string, unknown>) {
  switch (msg.type) {
    case 'connected':
      console.log('WS connected:', msg.message);
      break;

    case 'groups':
      groups = (msg.groups as typeof groups) || [];
      renderGroups();
      break;

    case 'message': {
      const incoming = {
        id: msg.id as string,
        chat_jid: msg.chatJid as string,
        sender: msg.sender as string,
        sender_name: (msg.sender_name as string) || (msg.sender as string),
        content: msg.content as string,
        timestamp: msg.timestamp as string,
        is_from_me: (msg.is_from_me as boolean) || false,
        is_bot_message: (msg.is_bot_message as boolean) || false,
      };
      // Only append if it belongs to the current group
      if (incoming.chat_jid === currentGroupJid) {
        messages.push(incoming);
        renderMessages();
      }
      // Notification for other groups
      if (incoming.chat_jid !== currentGroupJid && !incoming.is_from_me) {
        notifyAgent(incoming as { sender_name: string; content: string; chat_jid: string });
      }
      break;
    }

    case 'typing':
      typingIndicator.className = (msg.isTyping as boolean) ? '' : 'hidden';
      break;

    case 'error':
      console.error('WS error from server:', msg.message);
      showError(`Server error: ${msg.message}`);
      break;
  }
}

function notifyAgent(msg: { sender_name: string; content: string; chat_jid: string }) {
  const group = groups.find((g) => g.jid === msg.chat_jid);
  const title = `${group?.name || 'NanoClaw Agent'}`;
  const body = `${msg.sender_name}: ${(msg.content as string).slice(0, 100)}`;
  if (typeof window !== 'undefined' && (window as any).nanoclawApp) {
    (window as any).nanoclawApp.notify(title, body);
  }
}

// --- Actions ---
async function selectGroup(jid: string) {
  currentGroupJid = jid;
  messages = [];
  renderMessages();
  updateChatHeader();
  renderGroups();
  await loadMessages();
  await loadTasks();
  sendWs({ type: 'select_group', chatJid: jid });
}

async function sendMessage(content: string) {
  if (!content.trim() || !currentGroupJid) return;

  sendWs({ type: 'message', chatJid: currentGroupJid, content: content.trim() });

  // Optimistically add user message
  const userMsg = {
    id: `opt_${Date.now()}`,
    chat_jid: currentGroupJid,
    sender: 'me',
    sender_name: 'You',
    content: content.trim(),
    timestamp: Date.now().toString(),
    is_from_me: true,
    is_bot_message: false,
  };
  messages.push(userMsg);
  renderMessages();
  messageInput.value = '';
  autoResizeInput();
}

async function uploadFile(file: File) {
  if (!currentGroupJid) return;
  const formData = new FormData();
  formData.append('file', file);

  try {
    const headers: Record<string, string> = {};
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const res = await fetch(
      `http://localhost:3000/api/upload?jid=${encodeURIComponent(currentGroupJid)}`,
      { method: 'POST', headers, body: formData },
    );
    if (!res.ok) throw new Error(`Upload failed: ${res.status}`);
    const data = (await res.json()) as { ok: boolean; files: Array<{ name: string; path: string }> };
    // Send a message referencing the uploaded file
    const fileRef = `📎 Uploaded: ${data.files[0]?.name || file.name}`;
    await sendMessage(fileRef);
  } catch (err) {
    showError(`Upload failed: ${err}`);
  }
}

function showError(msg: string) {
  // Flash a toast-like error in the messages area
  const el = document.createElement('div');
  el.className = 'message system';
  el.textContent = `⚠ ${msg}`;
  messagesEl.appendChild(el);
  messagesEl.scrollTop = messagesEl.scrollHeight;
  setTimeout(() => el.remove(), 5000);
}

// --- Input helpers ---
function autoResizeInput() {
  messageInput.style.height = 'auto';
  messageInput.style.height = Math.min(messageInput.scrollHeight, 120) + 'px';
}

// --- Event Listeners ---
tokenConnectBtn.addEventListener('click', () => {
  token = tokenInput.value.trim();
  // Transition to main screen
  tokenScreen.classList.add('hidden');
  mainScreen.classList.remove('hidden');
  // Connect and load
  connectWS();
  loadGroups();
});

tokenInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') {
    e.preventDefault();
    tokenConnectBtn.click();
  }
});

sidebarCollapse.addEventListener('click', () => {
  sidebar.classList.toggle('collapsed');
  sidebarCollapse.textContent = sidebar.classList.contains('collapsed') ? '›' : '‹';
});

refreshGroupsBtn.addEventListener('click', () => {
  loadGroups();
  if (currentGroupJid) loadMessages();
});

sendBtn.addEventListener('click', () => {
  sendMessage(messageInput.value);
});

messageInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    sendMessage(messageInput.value);
  }
});

messageInput.addEventListener('input', autoResizeInput);

attachBtn.addEventListener('click', () => {
  fileInput.click();
});

fileInput.addEventListener('change', () => {
  for (const file of fileInput.files || []) {
    uploadFile(file);
  }
  fileInput.value = '';
});

// Drag and drop
document.addEventListener('dragover', (e) => {
  e.preventDefault();
  if (currentGroupJid) fileDropZone.classList.remove('hidden');
});

document.addEventListener('dragleave', (e) => {
  if (!e.relatedTarget) fileDropZone.classList.add('hidden');
});

document.addEventListener('drop', (e) => {
  e.preventDefault();
  fileDropZone.classList.add('hidden');
  if (!currentGroupJid) return;
  for (const file of e.dataTransfer?.files || []) {
    uploadFile(file);
  }
});

clearChatBtn.addEventListener('click', () => {
  messages = [];
  renderMessages();
});

// Auto-focus message input when main screen is shown
mainScreen.addEventListener('transitionend', () => {
  if (!mainScreen.classList.contains('hidden')) {
    messageInput.focus();
  }
});
